336	
337	        return exists ? null : $"wpId '{wpId}'가 WP-REGISTRY.json에 등록되지 않았습니다 — WP 추가는 사람 결재입니다";
338	    }
339	
340	    // CLI 인수를 파싱한다. 필수 인수(transition-id·expected-workstate-sha256·request)가 없으면 null 반환.
341	    private static ApplierOptions? ParseArgs(string[] args)
342	    {
343	        var map = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
344	        for (var i = 1; i < args.Length - 1; i++)
345	        {
346	            if (args[i].StartsWith("--", StringComparison.Ordinal))
347	                map[args[i][2..]] = args[i + 1];
348	        }
349	
350	        if (!map.TryGetValue("transition-id", out var tid) || string.IsNullOrWhiteSpace(tid)) return null;
351	        if (!map.TryGetValue("expected-workstate-sha256", out var sha) || string.IsNullOrWhiteSpace(sha)) return null;
352	        if (!map.TryGetValue("request", out var req) || string.IsNullOrWhiteSpace(req)) return null;
353	
354	        map.TryGetValue("verdict", out var verdict);
355	        map.TryGetValue("human-decision", out var humanDec);
356	        return new ApplierOptions(tid, sha, req, verdict, humanDec);
357	    }
358	
359	    // appliedTransitions에서 transition-id 중복 여부를 확인한다.
360	    private static bool IsAlreadyApplied(JsonObject workstate, string transitionId)
361	    {
362	        var applied = workstate["appliedTransitions"] as JsonArray;
363	        if (applied is null) return false;
364	        return applied.OfType<JsonObject>().Any(o =>
365	            string.Equals(o["id"]?.ToString(), transitionId, StringComparison.OrdinalIgnoreCase));
366	    }
367	
368	    // 이미 적용된 transition-id에 대한 idempotent 응답을 출력하고 0을 반환한다.
369	    private static int ReportIdempotent(string transitionId)
370	    {
371	        Console.WriteLine(new JsonObject
372	        {
373	            ["ok"] = true,
374	            ["transitionId"] = transitionId,
375	            ["idempotent"] = true,
376	            ["note"] = "이 transition-id는 이미 적용됐다 — 상태를 바꾸지 않는다",
377	        }.ToJsonString(WriteOptions));
378	        return 0;
379	    }
380	
381	    // post-apply 단계 실패 메시지를 JSON 문자열로 만든다.
382	    private static string PostApplyError(string tid, string failure, int exitCode, bool wsApplied, bool projApplied)
383	    {
384	        var note = projApplied
385	            ? "WORKSTATE와 projection은 갱신됐으나 handoff-integrity가 실패했다"
386	            : "WORKSTATE는 갱신됐으나 projection이 실패했다 — projection을 수동으로 재실행하라";
387	        return new JsonObject
388	        {
389	            ["transitionId"] = tid,
390	            ["phase"] = "post-apply",
391	            ["failure"] = failure,
392	            ["exitCode"] = exitCode,
393	            ["workstateApplied"] = wsApplied,
394	            ["projectionApplied"] = projApplied,
395	            ["note"] = note,
396	        }.ToJsonString();
397	    }
398	
399	    // 전이 결과를 WORKSTATE.applier-log.jsonl에 한 줄 추가한다(append-only).
400	    private static void AppendApplierLog(string logPath, string transitionId, string result, int exitCode)
401	    {
402	        var entry = new JsonObject
403	        {
404	            ["transitionId"] = transitionId,
405	            ["result"] = result,
406	            ["exitCode"] = exitCode,
407	            ["at"] = DateTime.UtcNow.ToString("o"),
408	        };
409	        File.AppendAllText(logPath, entry.ToJsonString() + "\n", new UTF8Encoding(false));
410	    }
411	
412	    // stderr에 JSON 오류 메시지를 출력한다.
413	    private static void WriteError(string message)
414	        => Console.Error.WriteLine($"{{\"error\":\"{message}\"}}");
415	
416	    // 실패 결과를 stderr에 출력하고 지정 exit code를 반환한다.
417	    private static int Fail(int exitCode, string transitionId, string reason, string detail)
418	    {
