# dry-run 후 WORKSTATE 무변경 확인
\$bytes = [System.IO.File]::ReadAllBytes('docs\handoff\WORKSTATE.json')
\$sha = [System.Security.Cryptography.SHA256]::Create()
\$hash = \$sha.ComputeHash(\$bytes)
\$hex = (\$hash | ForEach-Object { \$_.ToString('x2') }) -join ''
if (\$hex -eq 'f6f6645db4ef624b01a16189f7cb77c7c906506dc95644028a4d1af1d6a3b693') {
    Write-Output \"WORKSTATE 무변경: PASS\"
} else {
    Write-Output \"WORKSTATE 변경됨: FAIL (\$hex)\"
}
"

powershell -NoProfile -Command "
# Get-Allowlist 함수 정의 (run-executor.ps1과 동일)
function Get-Allowlist([string]\$directivePath) {
  if ([string]::IsNullOrWhiteSpace(\$directivePath) -or -not (Test-Path \$directivePath)) { return ,@() }
  \$lines = Get-Content \$directivePath -Encoding UTF8
  \$inSection = \$false
  \$paths = @()
  foreach (\$l in \$lines) {
    if (\$l -match '^##\s+허용 파일') { \$inSection = \$true; continue }
    if (\$inSection -and \$l -match '^##\s') { break }
    if (\$inSection -and \$l -match '^\s*-\s+(\S+)') {
      \$p = \$matches[1].Trim('\`')
      if (\$p -notmatch '^\(') { \$paths += \$p }
    }
  }
  return ,\$paths
}

# 시험 6: allowlist 섹션 없는 가짜 지시서
\$fakeDir = 'C:\Users\1\Documents\Local-First Workflow Dashboard\docs\handoff\queue'
\$fakePath = Join-Path \$fakeDir 'directive-FAKE-99-noallowlist.md'
'# FAKE-99 -- no allowlist section' | Set-Content \$fakePath -Encoding UTF8

\$allow = Get-Allowlist \$fakePath
Write-Output \"시험6: allowlist count=\$(\$allow.Count) (0이어야 함)\"

# 발사 중단 guard가 작동하는지 확인
if (\$allow.Count -eq 0) {
    try {
        throw '발사 중단 guard TEST'
    } catch {
        Write-Output '시험6: 발사 중단 throw 작동 확인 PASS'
    }
}
Remove-Item \$fakePath -Force

# 시험 7: DI-00-01 지시서에서 9개 추출
\$diPath = 'C:\Users\1\Documents\Local-First Workflow Dashboard\docs\handoff\queue\directive-DI-00-01-worktracking.md'
if (Test-Path \$diPath) {
    \$allow7 = Get-Allowlist \$diPath
    Write-Output \"시험7: allowlist count=\$(\$allow7.Count) (9이어야 함)\"
    \$allow7 | ForEach-Object { Write-Output \"  - \$_\" }
} else {
    Write-Output '시험7: 지시서 파일 없음'
}
"

powershell -NoProfile -Command "
# 임시 가짜 지시서 (큐 디렉터리 밖에)
\$fakeDirPath = 'C:\Temp\guard01-fake-directive.md'
'# FAKE-NO-ALLOWLIST -- allowlist 절 없음' | Set-Content \$fakeDirPath -Encoding UTF8

# run-executor.ps1의 guard 부분만 격리 실행
function Get-Allowlist([string]\$directivePath) {
  if ([string]::IsNullOrWhiteSpace(\$directivePath) -or -not (Test-Path \$directivePath)) { return ,@() }
  \$lines = Get-Content \$directivePath -Encoding UTF8
  \$inSection = \$false
  \$paths = @()
  foreach (\$l in \$lines) {
    if (\$l -match '^##\s+허용 파일') { \$inSection = \$true; continue }
    if (\$inSection -and \$l -match '^##\s') { break }
    if (\$inSection -and \$l -match '^\s*-\s+(\S+)') {
      \$p = \$matches[1].Trim('\`')
      if (\$p -notmatch '^\(') { \$paths += \$p }
    }
  }
  return ,\$paths
}

# run-executor.ps1 guard 시뮬레이션
\$dPath = \$fakeDirPath
\$TaskId = 'FAKE-99'
try {
    \$allow = Get-Allowlist \$dPath
    if (\$allow.Count -eq 0) {
        throw \"발사 중단: Get-Allowlist가 빈 배열을 반환했다 — 지시서: \$dPath ('^## 허용 파일' 섹션이 있는지, BOM 인코딩인지 확인하라)\"
    }
    Write-Output '오류: guard가 작동하지 않았다'
} catch {
    Write-Output \"시험6 PASS: 발사 중단 throw 발생\"
    Write-Output \"  메시지: \$_\"
}
Remove-Item \$fakeDirPath -Force
"

